from dataclasses import dataclass, field
from typing import Dict

# Unit costs — tune these to your actual infrastructure
UNIT_COSTS = {
    "loki_per_gb_stored": 0.023,       # S3/GCS object storage per GB
    "loki_per_gb_ingest": 0.008,       # compute for distributor + ingester per GB
    "tempo_per_million_spans": 0.04,   # compute + storage for Tempo
    "prometheus_per_1k_series": 0.015, # compute + storage for Prometheus/Thanos
    "platform_overhead_monthly": 800,  # Grafana, Alertmanager, collector base fleet
}

@dataclass
class TeamUsage:
    team: str
    loki_gb_ingested: float      # bytes ingested / 1e9
    loki_gb_stored: float        # compressed bytes in object store / 1e9
    tempo_million_spans: float   # spans received / 1e6
    prometheus_k_series: float   # active series / 1e3
    usage_share: float = 0.0     # fraction of total platform usage (set after all teams loaded)

    @property
    def loki_cost(self) -> float:
        return (self.loki_gb_ingested * UNIT_COSTS["loki_per_gb_ingest"] +
                self.loki_gb_stored * UNIT_COSTS["loki_per_gb_stored"])

    @property
    def tempo_cost(self) -> float:
        return self.tempo_million_spans * UNIT_COSTS["tempo_per_million_spans"]

    @property
    def prometheus_cost(self) -> float:
        return self.prometheus_k_series * UNIT_COSTS["prometheus_per_1k_series"]

    @property
    def overhead_share(self) -> float:
        return UNIT_COSTS["platform_overhead_monthly"] * self.usage_share

    @property
    def total_cost(self) -> float:
        return self.loki_cost + self.tempo_cost + self.prometheus_cost + self.overhead_share


def compute_chargeback(teams: list[TeamUsage]) -> list[TeamUsage]:
    """Assign overhead share proportionally to variable cost."""
    total_variable = sum(t.loki_cost + t.tempo_cost + t.prometheus_cost for t in teams)
    for team in teams:
        variable = team.loki_cost + team.tempo_cost + team.prometheus_cost
        team.usage_share = variable / total_variable if total_variable > 0 else 1 / len(teams)
    return teams


# Example
usages = [
    TeamUsage("genai-search",     loki_gb_ingested=42, loki_gb_stored=18, tempo_million_spans=6.2,  prometheus_k_series=4.2),
    TeamUsage("genai-summarise",  loki_gb_ingested=65, loki_gb_stored=28, tempo_million_spans=8.5,  prometheus_k_series=6.1),
    TeamUsage("ml-platform",      loki_gb_ingested=18, loki_gb_stored=8,  tempo_million_spans=2.6,  prometheus_k_series=2.8),
]
compute_chargeback(usages)
for u in usages:
    print(f"{u.team:<22} logs=${u.loki_cost:>6.0f}  traces=${u.tempo_cost:>6.0f}  "
          f"metrics=${u.prometheus_cost:>5.0f}  overhead=${u.overhead_share:>5.0f}  "
          f"total=${u.total_cost:>7.0f}")

import requests, datetime, smtplib
from email.mime.text import MIMEText

PROMETHEUS_URL = "http://prometheus:9090"
BUDGETS = {
    "genai-search":    800,
    "genai-summarise": 1200,
    "ml-platform":     500,
}
TEAM_EMAILS = {
    "genai-search":    "genai-search-lead@example.com",
    "genai-summarise": "summarise-lead@example.com",
    "ml-platform":     "ml-platform-lead@example.com",
}

def query_prometheus(expr: str) -> dict:
    r = requests.get(f"{PROMETHEUS_URL}/api/v1/query",
                     params={"query": expr}).json()
    return {item["metric"].get("team", "unknown"): float(item["value"][1])
            for item in r.get("data", {}).get("result", [])}

def generate_monthly_report() -> list[dict]:
    loki_gb = query_prometheus(
        'sum by (team) (increase(loki_distributor_bytes_received_total[30d])) / 1e9'
    )
    tempo_m_spans = query_prometheus(
        'sum by (team) (increase(tempo_distributor_spans_received_total[30d])) / 1e6'
    )
    prom_k_series = query_prometheus(
        'count by (team) ({__name__=~".+"}) / 1e3'
    )

    all_teams = set(loki_gb) | set(tempo_m_spans) | set(prom_k_series)
    usages = [
        TeamUsage(
            team=team,
            loki_gb_ingested=loki_gb.get(team, 0),
            loki_gb_stored=loki_gb.get(team, 0) * 0.43,   # retention factor
            tempo_million_spans=tempo_m_spans.get(team, 0),
            prometheus_k_series=prom_k_series.get(team, 0),
        )
        for team in all_teams
    ]
    compute_chargeback(usages)

    return [
        {
            "team": u.team,
            "loki_cost": round(u.loki_cost, 2),
            "tempo_cost": round(u.tempo_cost, 2),
            "prometheus_cost": round(u.prometheus_cost, 2),
            "overhead": round(u.overhead_share, 2),
            "total": round(u.total_cost, 2),
            "budget": BUDGETS.get(u.team),
            "over_budget": u.total_cost > (BUDGETS.get(u.team) or float("inf")),
        }
        for u in usages
    ]

def send_team_report(row: dict):
    email = TEAM_EMAILS.get(row["team"])
    if not email:
        return
    status = "⚠️ OVER BUDGET" if row["over_budget"] else "✅ Within budget"
    body = f"""
Observability Platform — Monthly Cost Report

Team: {row['team']}
Month: {datetime.date.today().strftime('%B %Y')}

  Logs (Loki):        ${row['loki_cost']:>8,.2f}
  Traces (Tempo):     ${row['tempo_cost']:>8,.2f}
  Metrics (Prom):     ${row['prometheus_cost']:>8,.2f}
  Platform overhead:  ${row['overhead']:>8,.2f}
  ─────────────────────────────
  Total:              ${row['total']:>8,.2f}
  Budget:             ${row.get('budget', 'N/A'):>8}
  Status: {status}

Optimisation guide: https://wiki.example.com/observability/cost-optimisation
Questions: #observability-platform
"""
    msg = MIMEText(body)
    msg["Subject"] = f"[Observability] {row['team']} cost report — {status}"
    msg["From"] = "observability-platform@example.com"
    msg["To"] = email
    # with smtplib.SMTP("smtp.example.com") as s:
    #     s.sendmail(msg["From"], [email], msg.as_string())
    print(f"Would send to {email}:\n{body}")

if __name__ == "__main__":
    rows = generate_monthly_report()
    for row in rows:
        send_team_report(row)
